TRANSLATIONS = {}
TRANSLATIONS["V14-P003"] = "\u5929\u5c71\u6709\u4e00\u4f4d\u795e\uff0c\u540d\u53eb\u6d51\u6c34\u6556\u3002\u5b83\u7684\u5f62\u72b6\u50cf\u53e3\u888b\uff0c\u901a\u4f53\u53d1\u5149\uff0c\u90a3\u5149\u4eae\u5982\u540c\u706b\u7130\u3002\u5b83\u6709\u516d\u53ea\u811a\u3001\u91cd\u53e0\u7684\u7fc5\u8180\uff0c\u6ca1\u6709\u9762\u76ee\u3002\u5b83\u8fa8\u8bc6\uff08\u4e00\u8bf4\u201c\u55dc\u597d\u201d\uff09\u6b4c\u821e\uff0c\u5176\u5b9e\u5c31\u662f\u5e1d\u6c5f\u3002\u5211\u5929\u4e0e\u5929\u5e1d\u4e89\u593a\u795e\u4f4d\uff0c\u5929\u5e1d\u780d\u4e0b\u4e86\u4ed6\u7684\u5934\u9885\uff0c\u57cb\u8462\u5728\u5e38\u7f8a\u5c71\u3002\u5211\u5929\u4fbf\u4ee5\u53cc\u4e73\u4e3a\u76ee\uff0c\u4ee5\u809a\u8110\u4e3a\u53e3\uff0c\u624b\u6301\u5e72\u621a\u7fe5\u65a7\u7ee7\u7eed\u8d77\u821e\u3002"
TRANSLATIONS["V14-P006"] = "\u5929\u7fc1\u59d3\u5f20\u540d\u575a\uff0c\u5b57\u523a\u6e34\uff0c\u6e14\u9633\u4eba\u3002\u4ed6\u5e74\u5c11\u65f6\u4e0d\u5b88\u89c4\u77e9\uff0c\u4e0d\u53d7\u4efb\u4f55\u62d8\u675f\u3002\u4ed6\u66fe\u5f20\u7f51\u6355\u5f97\u4e00\u53ea\u767d\u96c0\uff0c\u5341\u5206\u559c\u7231\u4fbf\u517b\u4e86\u8d77\u6765\u3002\u68a6\u4e2d\u5929\u4e0a\u7684\u5218\u7fc1\u5bf9\u4ed6\u5927\u53d1\u96f7\u9706\uff0c\u6bcf\u6b21\u60f3\u8981\u6740\u4ed6\uff0c\u767d\u96c0\u603b\u4f1a\u4e8b\u5148\u62a5\u4fe1\u7ed9\u5f20\u575a\uff0c\u5f20\u575a\u4e8e\u662f\u8bbe\u4e0b\u5404\u79cd\u9632\u5907\uff0c\u6700\u7ec8\u5218\u7fc1\u59cb\u7ec8\u65e0\u6cd5\u52a0\u5bb3\u4e8e\u4ed6\u3002\u5218\u7fc1\u4e8e\u662f\u4eb2\u81ea\u4e0b\u754c\u6765\u67e5\u770b\uff0c\u5f20\u575a\u76db\u8bbe\u5bb4\u5e2d\u6b3e\u5f85\uff0c\u7136\u540e\u8d81\u673a\u7a83\u9a91\u4e86\u5218\u7fc1\u7684\u8f66\u9a7e\uff0c\u4e58\u767d\u9f99\u6325\u97ad\u76f4\u4e0a\u4e5d\u5929\u3002\u5929\u516c\u4e58\u7740\u5176\u4f59\u7684\u9f99\u8ffd\u8d76\uff0c\u5374\u6ca1\u6709\u8ffd\u4e0a\u3002\u5f20\u575a\u5230\u8fbe\u5929\u5bab\u4e4b\u540e\uff0c\u4fbf\u66f4\u6362\u4e86\u767e\u5b98\uff0c\u5c01\u95ed\u4e86\u5317\u5929\u95e8\uff0c\u5c01\u767d\u96c0\u4e3a\u4e0a\u537f\u4faf\uff0c\u66f4\u6539\u767d\u96c0\u7684\u540e\u4ee3\u4f7f\u5176\u4e0d\u518d\u964d\u751f\u4eba\u95f4\u3002\u5218\u7fc1\u5931\u53bb\u4e86\u6cbb\u7406\u4e4b\u6743\uff0c\u4fbf\u5f98\u5f8a\u4e8e\u4e94\u5cb3\u4e4b\u95f4\u5174\u707e\u4f5c\u7978\u3002\u5f20\u575a\u5bf9\u6b64\u9887\u4e3a\u5fe7\u8651\uff0c\u4e8e\u662f\u4efb\u547d\u5218\u7fc1\u4e3a\u6cf0\u5c71\u592a\u5b88\uff0c\u638c\u7ba1\u751f\u6b7b\u7c3f\u7c4d\u3002"
TRANSLATIONS["V14-P010"] = "\u7076\u795e\u540d\u53eb\u9697\uff0c\u5f62\u8c8c\u5982\u540c\u7f8e\u5973\u3002\u53c8\u8bf4\u4ed6\u59d3\u5f20\u540d\u5355\uff0c\u5b57\u5b50\u90ed\u3002\u4ed6\u7684\u592b\u4eba\u5b57\u537f\u5fcc\uff0c\u6709\u516d\u4e2a\u5973\u513f\uff0c\u90fd\u540d\u53eb\u5bdf\uff08\u4e00\u4f5c\u796d\uff09\u6d3d\u3002\u7076\u795e\u5e38\u5728\u6bcf\u6708\u6700\u540e\u4e00\u5929\u4e0a\u5929\u79aa\u544a\u4eba\u7684\u7f6a\u72b6\uff0c\u7f6a\u5927\u7684\u51cf\u5bff\u4e00\u7eaa\uff08\u4e09\u767e\u65e5\uff09\uff0c\u7f6a\u5c0f\u7684\u51cf\u5bff\u4e00\u7b97\uff08\u4e00\u767e\u65e5\uff09\u3002\u4ed6\u672c\u662f\u5929\u5e1d\u7684\u7763\u4f7f\uff0c\u5728\u4e0b\u754c\u5219\u4e3a\u5730\u7cbe\u3002\u5df3\u4e11\u65e5\uff0c\u65e5\u51fa\u536f\u65f6\u5347\u5929\uff0c\u5230\u65e5\u4e2d\u4fbf\u4e0b\u5230\u5404\u7f72\u529e\u516c\uff0c\u5728\u8fd9\u4e00\u5929\u796d\u7960\u7076\u795e\u53ef\u5f97\u798f\u3002\u4ed6\u5c5e\u4e0b\u7684\u795e\u7075\u6709\u5929\u5e1d\u5a07\u5b59\u3001\u5929\u5e1d\u5927\u592b\u3001\u5929\u5e1d\u90fd\u5c09\u3001\u5929\u5e1d\u957f\u5144\u3001\u7847\u4e0a\u7ae5\u5b50\u3001\u7a81\u4e0a\u7d2b\u5bab\u541b\u3001\u592a\u548c\u541b\u3001\u7389\u6c60\u592b\u4eba\u7b49\u3002\u4e00\u8bf4\u7076\u795e\u540d\u53eb\u58e4\u5b50\u3002"
TRANSLATIONS["V14-P014"] = "\u53e4\u9f9f\u5179\u56fd\u738b\u963f\u4e3b\u513f\uff0c\u6709\u795e\u5f02\u7684\u6cd5\u529b\uff0c\u80fd\u591f\u964d\u4f0f\u6bd2\u9f99\u3002\u5f53\u65f6\u6709\u5546\u4eba\u5728\u96c6\u5e02\u4e0a\u4e70\u4e86\u91d1\u94f6\u5b9d\u8d27\uff0c\u5230\u4e86\u534a\u591c\uff0c\u94b1\u5168\u90fd\u53d8\u6210\u4e86\u70ad\u3002\u56fd\u5883\u4e4b\u5185\u6570\u767e\u5bb6\u90fd\u4e22\u5931\u4e86\u91d1\u94f6\u8d22\u5b9d\u3002\u56fd\u738b\u6709\u4e2a\u513f\u5b50\u5148\u524d\u51fa\u4e86\u5bb6\uff0c\u4fee\u6210\u4e86\u963f\u7f57\u6c49\u679c\u4f4d\u3002\u56fd\u738b\u53bb\u95ee\u4ed6\uff0c\u7f57\u6c49\u8bf4\uff1a\u201c\u8fd9\u662f\u9f99\u5e72\u7684\u3002\u9f99\u4f4f\u5728\u5317\u5c71\uff0c\u9f99\u5934\u50cf\u864e\uff0c\u6b64\u523b\u6b63\u5728\u67d0\u5904\u7761\u89c9\u3002\u201d\u56fd\u738b\u4e8e\u662f\u6362\u4e86\u8863\u670d\uff0c\u6301\u5251\u60c4\u60c4\u51fa\u95e8\u3002\u5230\u4e86\u9f99\u7684\u4f4f\u5904\uff0c\u770b\u89c1\u9f99\u6b63\u5367\u7740\uff0c\u521a\u8981\u65a9\u6740\u5b83\uff0c\u53c8\u8f6c\u5ff5\u4e00\u60f3\uff1a\u201c\u6211\u65a9\u6740\u4e00\u6761\u7761\u9f99\uff0c\u8c01\u80fd\u77e5\u9053\u6211\u6709\u795e\u529b\uff1f\u201d\u4e8e\u662f\u5927\u58f0\u53f1\u559d\uff0c\u9f99\u60ca\u8dc3\u800c\u8d77\uff0c\u53d8\u4f5c\u4e00\u5934\u72ee\u5b50\uff0c\u56fd\u738b\u968f\u5373\u9a91\u4e86\u4e0a\u53bb\u3002\u9f99\u5927\u6012\uff0c\u53d1\u51fa\u96f7\u9e23\u4e4b\u58f0\uff0c\u817e\u7a7a\u98de\u5230\u57ce\u5317\u4e8c\u5341\u91cc\u5904\u3002\u56fd\u738b\u5bf9\u9f99\u8bf4\uff1a\u201c\u4f60\u82e5\u4e0d\u964d\u670d\uff0c\u6211\u5c31\u780d\u4e0b\u4f60\u7684\u5934\u3002\u201d\u9f99\u60e7\u6015\u56fd\u738b\u7684\u795e\u529b\uff0c\u4fbf\u8bf4\u4eba\u8bdd\u9053\uff1a\u201c\u4e0d\u8981\u6740\u6211\uff0c\u6211\u613f\u610f\u7ed9\u56fd\u738b\u5f53\u5750\u9a91\uff0c\u60f3\u8981\u53bb\u54ea\u91cc\uff0c\u968f\u5fc3\u5373\u5230\u3002\u201d\u56fd\u738b\u7b54\u5e94\u4e86\u3002\u6b64\u540e\u56fd\u738b\u4fbf\u5e38\u5e38\u4e58\u9f99\u51fa\u884c\u3002"
TRANSLATIONS["V15-P001"] = "\u548c\u5dde\u5218\u5f55\u4e8b\uff0c\u5927\u5386\u5e74\u95f4\u7f62\u5b98\u540e\u4f4f\u5728\u548c\u5dde\u65c1\u53bf\u3002\u4ed6\u996d\u91cf\u62b5\u5f97\u4e0a\u597d\u51e0\u4e2a\u4eba\uff0c\u5c24\u5176\u64c5\u957f\u5403\u9c4d\uff08\u751f\u9c7c\u7247\uff09\uff0c\u5e38\u8bf4\u9c4d\u7684\u7f8e\u5473\u4ece\u672a\u8ba9\u4ed6\u89c9\u5f97\u5403\u9971\u8fc7\u3002\u53bf\u4e2d\u95e8\u5ba2\u4fbf\u7f51\u4e86\u4e00\u767e\u591a\u65a4\u9c7c\uff0c\u5728\u91ce\u4ead\u805a\u4f1a\uff0c\u770b\u4ed6\u52a8\u7b77\u8fdb\u98df\u3002\u4ed6\u521a\u5f00\u59cb\u5403\u4e86\u51e0\u53e0\u9c4d\uff0c\u5ffd\u7136\u50cf\u88ab\u54fd\u4f4f\u4e86\uff0c\u54af\u51fa\u4e00\u9897\u9aa8\u73e0\u5b50\uff0c\u5927\u5982\u9ed1\u8c46\uff0c\u4fbf\u653e\u5728\u8336\u74ef\u4e2d\uff0c\u7528\u53e0\u5b50\u76d6\u4f4f\u3002\u9c4d\u8fd8\u6ca1\u5403\u5230\u4e00\u534a\uff0c\u5947\u602a\u7684\u4e8b\u53d1\u751f\u4e86\u2014\u2014\u76d6\u7740\u7684\u8336\u74ef\u503e\u659c\u6447\u6643\uff0c\u5218\u5f55\u4e8b\u6380\u5f00\u4e00\u770b\uff0c\u5148\u524d\u90a3\u9897\u9aa8\u73e0\u5df2\u7ecf\u957f\u5230\u597d\u51e0\u5bf8\u957f\u4e86\uff0c\u50cf\u4eba\u5f62\u3002\u5728\u5ea7\u7684\u5ba2\u4eba\u4e89\u76f8\u89c2\u770b\uff0c\u9aa8\u73e0\u968f\u7740\u4f17\u4eba\u7684\u6ce8\u89c6\u4e0d\u65ad\u589e\u957f\u3002\u9877\u523b\u4e4b\u95f4\u4fbf\u957f\u6210\u4e00\u4e2a\u4eba\u7684\u5927\u5c0f\uff0c\u968f\u5373\u653b\u51fb\u5218\u5f55\u4e8b\uff0c\u4ee4\u4ed6\u5455\u8840\u3002\u8fc7\u4e86\u5f88\u4e45\uff0c\u4e24\u4e2a\u9aa8\u4eba\u5404\u81ea\u6563\u5f00\u9003\u8d70\u2014\u2014\u4e00\u4e2a\u6cbf\u5385\u5802\u897f\u4fa7\u8dd1\uff0c\u4e00\u4e2a\u8f6c\u5385\u5802\u5de6\u4fa7\u8dd1\uff0c\u5230\u4e86\u540e\u95e8\u5904\u4e24\u76f8\u78b0\u649e\uff0c\u5408\u4e3a\u4e00\u4f53\uff0c\u6b63\u662f\u5218\u5f55\u4e8b\u672c\u4eba\uff0c\u53ea\u662f\u795e\u5fd7\u5df2\u7ecf\u75f4\u50bb\u4e86\u3002\u8fc7\u4e86\u534a\u5929\u624d\u80fd\u8bf4\u8bdd\uff0c\u95ee\u4ed6\u7f18\u7531\uff0c\u5168\u90fd\u8bb0\u4e0d\u5f97\u4e86\u3002\u4ece\u6b64\u4ee5\u540e\u4ed6\u4fbf\u538c\u6076\u5403\u9c4d\u4e86\u3002"

with open(DATA_FILE, encoding='utf-8') as f:
    data = json.load(f)

for s in data['stories']:
    pid = s['pid']
    if pid in TRANSLATIONS:
        s['translation'] = TRANSLATIONS[pid]
    else:
        s['translation'] = ""

data['translation_note'] = "\u4ee5\u4e0a\u767d\u8bdd\u8bd1\u6587\u7531AI\u751f\u6210\uff0c\u4ec5\u4f9b\u53c2\u8003"

with open(DATA_FILE, 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("Done. Added translations to story_data.json")
for s in data['stories']:
    print(f"  {s['pid']}: {len(s.get('translation',''))} chars")